from dataclasses import dataclass, field
from enum import Enum


class Enforcement(Enum):
    HARD = "hard"   # raise ConstraintViolation; loop must handle
    SOFT = "soft"   # log warning; loop continues


@dataclass
class Constraint:
    description: str
    enforcement: Enforcement = Enforcement.HARD

    def __str__(self) -> str:
        tag = "[HARD]" if self.enforcement == Enforcement.HARD else "[SOFT]"
        return f"{tag} {self.description}"


@dataclass
class ConstraintSet:
    """
    All constraints for one agent run. Serialised into the system prompt
    and also checked programmatically in the tool layer.
    """
    constraints: list[Constraint] = field(default_factory=list)

    def hard(self) -> list[Constraint]:
        return [c for c in self.constraints if c.enforcement == Enforcement.HARD]

    def soft(self) -> list[Constraint]:
        return [c for c in self.constraints if c.enforcement == Enforcement.SOFT]

    def to_prompt_section(self) -> str:
        """Format for injection into the system prompt constraints section."""
        lines = []
        for c in self.hard():
            lines.append(f"- {c.description}")
        if self.soft():
            lines.append("Guidelines (preferred but not enforced):")
            for c in self.soft():
                lines.append(f"  - {c.description}")
        return "Constraints:\n" + "\n".join(lines)


# Example:
constraints = ConstraintSet(constraints=[
    Constraint("Never modify files in tests/."),
    Constraint("Never add or remove packages from requirements.txt."),
    Constraint("Run the test suite after every file change."),
    Constraint("Keep changes minimal — fix only what is broken.", Enforcement.SOFT),
    Constraint("Prefer stdlib over third-party libraries.", Enforcement.SOFT),
])

class ConstraintViolation(Exception):
    """Raised when a hard constraint is violated inside a tool."""
    def __init__(self, constraint: str, attempted: str):
        self.constraint = constraint
        self.attempted = attempted
        super().__init__(f"Constraint violated: {constraint!r} — attempted: {attempted!r}")


def write_file(path: str, content: str) -> str:
    """Tool: write a file. Enforces path constraints before writing."""
    # Hard constraint: no writes outside /workspace
    if not path.startswith("/workspace/"):
        raise ConstraintViolation(
            constraint="Never write outside /workspace/",
            attempted=f"write_file({path!r})",
        )

    # Hard constraint: no writes to the test directory
    if "/tests/" in path or path.endswith("/tests"):
        raise ConstraintViolation(
            constraint="Never modify files in tests/",
            attempted=f"write_file({path!r})",
        )

    with open(path, "w") as f:
        f.write(content)
    return f"Written: {path}"


def run_sql(query: str, conn) -> list[dict]:
    """Tool: run a SQL query. Enforces read-only policy."""
    forbidden = ("INSERT", "UPDATE", "DELETE", "DROP", "ALTER", "CREATE", "TRUNCATE")
    upper = query.strip().upper()
    for keyword in forbidden:
        if upper.startswith(keyword):
            raise ConstraintViolation(
                constraint="SQL must be read-only (SELECT only)",
                attempted=f"run_sql starting with {keyword}",
            )
    cursor = conn.cursor()
    cursor.execute(query)
    return [dict(row) for row in cursor.fetchall()]

import anthropic

client = anthropic.Anthropic()


def run_agent(system: str, task: str, tools: list[dict]) -> str:
    """
    Agent loop that converts ConstraintViolation into a tool_result error
    so the model can adapt rather than crash the loop.
    """
    messages = [{"role": "user", "content": task}]

    for step in range(30):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            system=system,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return ""

        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue
            try:
                result = dispatch_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })
            except ConstraintViolation as e:
                # Return the violation as an error result — model sees it and
                # must choose a different approach. Loop continues.
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": f"ERROR: Constraint violated — {e.constraint}. Attempted: {e.attempted}. Choose a different approach.",
                    "is_error": True,
                })

        messages.append({"role": "user", "content": tool_results})

    return "Max steps reached."


def dispatch_tool(name: str, input: dict) -> str:
    if name == "write_file":
        return write_file(input["path"], input["content"])
    if name == "run_sql":
        return run_sql(input["query"], get_connection())
    raise ValueError(f"Unknown tool: {name}")

# Pattern 1: Path allowlist enforced in every file tool
ALLOWED_PATHS = ["/workspace/src/", "/workspace/tests/"]  # read: both; write: src/ only
WRITE_ALLOWED_PATHS = ["/workspace/src/"]

def _assert_path(path: str, allowed: list[str], op: str) -> None:
    if not any(path.startswith(p) for p in allowed):
        raise ConstraintViolation(
            constraint=f"{op} restricted to: {allowed}",
            attempted=f"{op}({path!r})",
        )


# Pattern 2: Operation allowlist (deny by default, permit explicitly)
PERMITTED_TOOLS = frozenset({"read_file", "write_file", "run_tests", "search_code"})

def dispatch_tool(name: str, input: dict) -> str:
    if name not in PERMITTED_TOOLS:
        raise ConstraintViolation(
            constraint=f"Only these tools are permitted: {sorted(PERMITTED_TOOLS)}",
            attempted=f"tool call: {name!r}",
        )
    return _tool_impls[name](input)


# Pattern 3: Rate limit — cap expensive tool calls per run
_tool_call_counts: dict[str, int] = {}
TOOL_CALL_LIMITS = {"run_tests": 10, "search_web": 5}

def rate_limited(name: str, fn, input: dict) -> str:
    limit = TOOL_CALL_LIMITS.get(name)
    if limit is not None:
        count = _tool_call_counts.get(name, 0)
        if count >= limit:
            raise ConstraintViolation(
                constraint=f"{name!r} may be called at most {limit} times per run",
                attempted=f"call #{count + 1}",
            )
        _tool_call_counts[name] = count + 1
    return fn(input)


# Pattern 4: Audit log — record every tool call for post-run inspection
import datetime

_audit_log: list[dict] = []

def audited(name: str, input: dict, result: str) -> None:
    _audit_log.append({
        "tool": name,
        "input": input,
        "result_snippet": result[:200],
        "ts": datetime.datetime.utcnow().isoformat(),
    })

import pytest


class TestConstraintViolation:
    def test_write_outside_workspace_raises(self):
        with pytest.raises(ConstraintViolation) as exc_info:
            write_file("/etc/passwd", "evil")
        assert "write outside /workspace/" in exc_info.value.constraint.lower()

    def test_write_to_tests_raises(self):
        with pytest.raises(ConstraintViolation):
            write_file("/workspace/tests/test_auth.py", "overwritten")

    def test_write_to_src_allowed(self, tmp_path, monkeypatch):
        # Monkeypatch the path check to use tmp_path as workspace
        monkeypatch.setattr("builtins.open", lambda p, m: open(str(tmp_path / "out.py"), m))
        # Should not raise when path starts with /workspace/src/
        # (full integration test would need a real /workspace mount)


class TestConstraintSet:
    def test_hard_and_soft_separated(self):
        cs = ConstraintSet(constraints=[
            Constraint("Never modify tests."),
            Constraint("Keep changes minimal.", Enforcement.SOFT),
        ])
        assert len(cs.hard()) == 1
        assert len(cs.soft()) == 1

    def test_prompt_section_contains_constraints(self):
        cs = ConstraintSet(constraints=[
            Constraint("Never modify tests."),
        ])
        prompt = cs.to_prompt_section()
        assert "Never modify tests." in prompt
        assert "Constraints:" in prompt

    def test_soft_guidelines_labelled(self):
        cs = ConstraintSet(constraints=[
            Constraint("Prefer stdlib.", Enforcement.SOFT),
        ])
        prompt = cs.to_prompt_section()
        assert "Guidelines" in prompt
